import java.io.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSecureCode {
    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "<script>alert('XSS Attack!')</script>";

            // Properly handling user input by encoding it before outputting it to an HTML page
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html>");
            out.println("<head><title>XSS Secure Page</title></head>");
            out.println("<body>");

            Encoder encoder = ESAPI.encoder();
            out.println("<h1>Welcome, " + encoder.encodeForHTML(userInput) + "</h1>");

            out.println("</body>");
            out.println("</html>");

            out.close();

        } catch (IOException e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }
}
